import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  TextInput,
  ScrollView,
  StyleSheet,
  Dimensions,
  FlatList,
  Animated,
  Alert,
} from 'react-native';
import { useIncidentStore, EmergencyContact } from '../store';
import {
  SafeAreaContainer,
  Header,
  Button,
  FormField,
  PermissionRow,
  ContactCard,
  Colors,
} from '../components/Layout';

const { width } = Dimensions.get('window');

// ─── Mock offline DB data (loads during splash) ──────────────────────────────
const OFFLINE_DB_MOCK = {
  hospitals: [{ name: 'District Hospital', lat: 0, lng: 0 }],
  police: [{ name: 'Police Station', number: '100' }],
};

// ─── SPLASH SCREEN ───────────────────────────────────────────────────────────
export const SplashScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const loadFromStorage = useIncidentStore((s) => s.loadFromStorage);
  const onboardingComplete = useIncidentStore((s) => s.onboardingComplete);
  const fade = useRef(new Animated.Value(0)).current;
  const scale = useRef(new Animated.Value(0.85)).current;

  useEffect(() => {
    // Animate in
    Animated.parallel([
      Animated.timing(fade, { toValue: 1, duration: 600, useNativeDriver: true }),
      Animated.spring(scale, { toValue: 1, tension: 60, friction: 10, useNativeDriver: true }),
    ]).start();

    // Load storage + navigate after 1.5s
    const init = async () => {
      await loadFromStorage();
      // offline DB already handled in store
    };
    init();

    const timer = setTimeout(() => {
      const fresh = useIncidentStore.getState().onboardingComplete;
      navigation.replace(fresh ? 'HomeMain' : 'OnboardingFlow');
    }, 1800);

    return () => clearTimeout(timer);
  }, []);

  return (
    <View style={ss.splashBg}>
      <Animated.View style={[ss.splashContent, { opacity: fade, transform: [{ scale }] }]}>
        <Text style={ss.splashIcon}>🚨</Text>
        <Text style={ss.splashTitle}>ROADSoS</Text>
        <Text style={ss.splashTagline}>Help finds you.</Text>
      </Animated.View>
      <View style={ss.splashFooter}>
        <Text style={ss.splashFooterText}>Emergency Response Network</Text>
      </View>
    </View>
  );
};

